,p_process_name=>'Load existing request'
,p_static_id=>'load-request'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'if PKG_SCAFF_REQ.can_edit(to_number(:P11_REQUEST_ID)) = ''N'' then',
'  raise_application_error(-20001, ''Not allowed'');',
'end if;',
'select po_id, contact_name, site_manager, gsm,',
'       vervoer_code, lader_code,',
'       to_char(delivery_date,''fmDDMonYYYY'',''NLS_DATE_LANGUAGE=ENGLISH''),',
'       delivery_hour,',
'       case when hold_flag = ''Y'' then ''Y'' else ''N'' end,',
'       remark',
'  into :P11_PO_ID, :P11_CONTACT, :P11_WERFLEIDER, :P11_GSM,',
'       :P11_VERVOER, :P11_LADER,',
'       :P11_DATUM, :P11_UUR, :P11_AANHOUDEN, :P11_OPMERKING',
'  from scaff_material_request',
' where request_id = to_number(:P11_REQUEST_ID);'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P11_REQUEST_ID'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>9813030771223724
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9210199130920274)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Save material request'
,p_static_id=>'save-material-request'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_datum date := to_date(:P11_DATUM,''DD-MON-YYYY'');',
'  l_min   date := PKG_SCAFF_REQ.next_business_day(trunc(sysdate),5);',
'  l_err   boolean := false;',
'begin',
'  if PKG_SCAFF_REQ.is_business_day(l_datum) = ''N'' then',
'    apex_error.add_error(',
'      p_message          => apex_lang.message(''SCAFF.MR.FORM.DATE.WEEKEND''),',
'      p_display_location => apex_error.c_inline_with_field_and_notif,',
'      p_page_item_name   => ''P11_DATUM'');',
'    l_err := true;',
'  end if;',
'  if l_datum < l_min then',
'    apex_error.add_error(',
'      p_message          => apex_lang.message(''SCAFF.MR.FORM.DATE.TOOSOON''),',
'      p_display_location => apex_error.c_inline_with_field_and_notif,',
'      p_page_item_name   => ''P11_DATUM'');',
'    l_err := true;',
'  end if;',
'  if l_err then',
'    return;',
'  end if;',
'',
'  if :P11_REQUEST_ID is null then',
'    insert into scaff_material_request (',
'      po_id, contact_name, site_manager, gsm,',
'      vervoer_code, lader_code,',
'      delivery_date, delivery_hour, hold_flag, remark',
'    ) values (',
'      to_number(:P11_PO_ID),',
'      :P11_CONTACT,',
'      :P11_WERFLEIDER,',
'      :P11_GSM,',
'      :P11_VERVOER,',
'      :P11_LADER,',
'      l_datum,',
'      :P11_UUR,',
'      case when :P11_AANHOUDEN in (''Y'',''1'') then ''Y'' else ''N'' end,',
'      :P11_OPMERKING',
'    );',
'    apex_application.g_print_success_message := apex_lang.message(''SCAFF.MR.FORM.SAVED'');',
'    for r in (',
'      select ''P11_CONTACT'' as nm from dual union all',
'      select ''P11_WERFLEIDER'' from dual union all',
'      select ''P11_GSM'' from dual union all',
'      select ''P11_VERVOER'' from dual union all',
'      select ''P11_LADER'' from dual union all',
'      select ''P11_DATUM'' from dual union all',
'      select ''P11_AANHOUDEN'' from dual union all',
'      select ''P11_OPMERKING'' from dual',
'    ) loop',
'      apex_util.set_session_state(r.nm, null);',
'    end loop;',
'  else',
'    if PKG_SCAFF_REQ.can_edit(to_number(:P11_REQUEST_ID)) = ''N'' then',
'      raise_application_error(-20001, ''Not allowed'');',
'    end if;',
'    update scaff_material_request',
'       set contact_name  = :P11_CONTACT,',
'           site_manager  = :P11_WERFLEIDER,',
'           gsm           = :P11_GSM,',
'           vervoer_code  = :P11_VERVOER,',
'           lader_code    = :P11_LADER,',
'           delivery_date = l_datum,',
'           delivery_hour = :P11_UUR,',
'           hold_flag     = case when :P11_AANHOUDEN in (''Y'',''1'') then ''Y'' else ''N'' end,',
'           remark        = :P11_OPMERKING',
'     where request_id = to_number(:P11_REQUEST_ID);',
'    apex_application.g_print_success_message := apex_lang.message(''SCAFF.MR.FORM.SAVED.UPDATE'');',
'  end if;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>9210199130920274
);
end;
