wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9826211622413179)
,p_process_sequence=>5
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Load existing return'
,p_static_id=>'load-return'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'if PKG_SCAFF_REQ.can_edit_return(to_number(:P21_RETURN_ID)) = ''N'' then',
'  raise_application_error(-20001, ''Not allowed'');',
'end if;',
'select po_id, contact_name, site_manager, gsm,',
'       bakken_count, transport_done,',
'       vervoer_code, lader_code,',
'       to_char(delivery_date,''fmDDMonYYYY'',''NLS_DATE_LANGUAGE=ENGLISH''),',
'       delivery_hour,',
'       case when hold_flag = ''Y'' then ''Y'' else ''N'' end,',
'       case when is_final = ''Y'' then ''Y'' else ''N'' end,',
'       remark',
'  into :P21_PO_ID, :P21_CONTACT, :P21_WERFLEIDER, :P21_GSM,',
'       :P21_BAKKEN, :P21_TRANSPORT_DONE,',
'       :P21_VERVOER, :P21_LADER,',
'       :P21_DATUM, :P21_UUR,',
'       :P21_AANHOUDEN, :P21_LAATSTE, :P21_OPMERKING',
'  from scaff_return_request',
' where return_id = to_number(:P21_RETURN_ID);'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P21_RETURN_ID'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>9826211622413179
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(9826367226413179)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Save return request'
,p_static_id=>'save-return-request'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_datum    date := to_date(:P21_DATUM,''DD-MON-YYYY'');',
'  l_min      date := PKG_SCAFF_REQ.next_business_day(trunc(sysdate),5);',
'  l_done     varchar2(1) := case when :P21_TRANSPORT_DONE in (''Y'',''1'') then ''Y'' else ''N'' end;',
'  l_hold     varchar2(1) := case when :P21_AANHOUDEN in (''Y'',''1'') then ''Y'' else ''N'' end;',
'  l_final    varchar2(1) := case when :P21_LAATSTE in (''Y'',''1'') then ''Y'' else ''N'' end;',
'  l_vervoer  varchar2(20) := case when l_done = ''Y'' then null else :P21_VERVOER end;',
'  l_lader    varchar2(20) := case when l_done = ''Y'' then null else :P21_LADER end;',
'  l_err      boolean := false;',
'begin',
'  -- Date rules only when transport NOT already done.',
'  if l_done = ''N'' then',
'    if PKG_SCAFF_REQ.is_business_day(l_datum) = ''N'' then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.MR.FORM.DATE.WEEKEND''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P21_DATUM'');',
'      l_err := true;',
'    end if;',
'    if l_datum < l_min then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.MR.FORM.DATE.TOOSOON''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P21_DATUM'');',
'      l_err := true;',
'    end if;',
'    if l_vervoer is null then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.RR.FORM.VERVOER.REQ''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P21_VERVOER'');',
'      l_err := true;',
'    end if;',
'    if l_lader is null then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.RR.FORM.LADER.REQ''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P21_LADER'');',
'      l_err := true;',
'    end if;',
'  end if;',
'  if l_err then',
'    return;',
'  end if;',
'',
'  if :P21_RETURN_ID is null then',
'    insert into scaff_return_request (',
'      po_id, contact_name, site_manager, gsm,',
'      bakken_count, transport_done,',
'      vervoer_code, lader_code,',
'      delivery_date, delivery_hour,',
'      hold_flag, is_final, remark',
'    ) values (',
'      to_number(:P21_PO_ID),',
'      :P21_CONTACT, :P21_WERFLEIDER, :P21_GSM,',
'      nvl(to_number(:P21_BAKKEN),0), l_done,',
'      l_vervoer, l_lader,',
'      l_datum, :P21_UUR,',
'      l_hold, l_final, :P21_OPMERKING',
'    );',
'    apex_application.g_print_success_message := apex_lang.message(''SCAFF.RR.FORM.SAVED'');',
'    for r in (',
'      select ''P21_CONTACT'' as nm from dual union all',
'      select ''P21_WERFLEIDER'' from dual union all',
'      select ''P21_GSM'' from dual union all',
'      select ''P21_BAKKEN'' from dual union all',
'      select ''P21_TRANSPORT_DONE'' from dual union all',
'      select ''P21_VERVOER'' from dual union all',
'      select ''P21_LADER'' from dual union all',
'      select ''P21_DATUM'' from dual union all',
'      select ''P21_AANHOUDEN'' from dual union all',
'      select ''P21_LAATSTE'' from dual union all',
'      select ''P21_OPMERKING'' from dual',
'    ) loop',
'      apex_util.set_session_state(r.nm, null);',
'    end loop;',
'  else',
'    if PKG_SCAFF_REQ.can_edit_return(to_number(:P21_RETURN_ID)) = ''N'' then',
'      raise_application_error(-20001, ''Not allowed'');',
'    end if;',
'    update scaff_return_request',
'       set contact_name   = :P21_CONTACT,',
'           site_manager   = :P21_WERFLEIDER,',
'           gsm            = :P21_GSM,',
'           bakken_count   = nvl(to_number(:P21_BAKKEN),0),',
'           transport_done = l_done,',
'           vervoer_code   = l_vervoer,',
'           lader_code     = l_lader,',
'           delivery_date  = l_datum,',
'           delivery_hour  = :P21_UUR,',
'           hold_flag      = l_hold,',
'           is_final       = l_final,',
'           remark         = :P21_OPMERKING',
'     where return_id = to_number(:P21_RETURN_ID);',
'    apex_application.g_print_success_message := apex_lang.message(''SCAFF.RR.FORM.SAVED.UPDATE'');',
'  end if;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>9826367226413179
);
end;
