prompt --application/pages/page_00031
begin
wwv_flow_imp_page.create_page(
 p_id=>31
,p_name=>'Transfer aanvraag - formulier'
,p_alias=>'TRANSFER-AANVRAAG-FORM'
,p_step_title=>'Transfer aanvraag'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'(function(){',
'  function addBizDays(d, n) {',
'    var x = new Date(d.getFullYear(), d.getMonth(), d.getDate());',
'    var left = n;',
'    while (left > 0) {',
'      x.setDate(x.getDate() + 1);',
'      var dow = x.getDay();',
'      if (dow !== 0 && dow !== 6) { left--; }',
'    }',
'    return x;',
'  }',
'  function iso(d){',
'    return d.getFullYear()+''-''+String(d.getMonth()+1).padStart(2,''0'')+''-''+String(d.getDate()).padStart(2,''0'');',
'  }',
'  var dp = document.getElementById(''P31_DATUM'');',
'  if (dp) {',
'    var minD = addBizDays(new Date(), 5);',
'    try { dp.setAttribute(''min-value'', iso(minD)); } catch(e) {}',
'    try { dp.setAttribute(''valid-example'', iso(minD)); } catch(e) {}',
'    dp.disabledDates = function(d){ var w = d.getDay(); return w === 0 || w === 6; };',
'  }',
'',
'  function syncTransport(){',
'    var v = apex.item(''P31_TRANSPORT_DONE'').getValue();',
'    var done = (v === ''Y'' || v === ''1'' || v === true);',
'    [''P31_VERVOER'',''P31_LADER''].forEach(function(it){',
'      var w = document.querySelector(''#''+it+''_CONTAINER, .t-Form-fieldContainer[data-for="''+it+''"]'');',
'      if (w) { w.style.display = done ? ''none'' : ''''; }',
'    });',
'    if (dp) {',
'      if (done) { try { dp.removeAttribute(''min-value''); } catch(e) {} dp.disabledDates = null; }',
'      else {',
'        var minD2 = addBizDays(new Date(), 5);',
'        try { dp.setAttribute(''min-value'', iso(minD2)); } catch(e) {}',
'        dp.disabledDates = function(d){ var w = d.getDay(); return w === 0 || w === 6; };',
'      }',
'    }',
'  }',
'  try { syncTransport(); } catch(e) {}',
'  apex.item(''P31_TRANSPORT_DONE'').element.on && apex.item(''P31_TRANSPORT_DONE'').element.on(''change'', syncTransport);',
'  document.getElementById(''P31_TRANSPORT_DONE'') && document.getElementById(''P31_TRANSPORT_DONE'').addEventListener(''change'', syncTransport);',
'',
'  var s = document.querySelector(''.t-Body-alert .t-Alert--success, #APEX_SUCCESS_MESSAGE .t-Alert--success'');',
'  if (!s) { return; }',
'  var txt = (s.textContent || '''').replace(/\s+/g,'''');',
'  if (!txt) { return; }',
'  var reqId = (apex.item(''P31_TRANSFER_ID'').getValue() || '''').toString();',
'  var targetPage = reqId ? ''50'' : ''30'';',
'  setTimeout(function(){',
'    try { apex.message.hidePageSuccess(); } catch(e) {}',
'    apex.navigation.redirect( apex.util.makeApplicationUrl({ pageId: targetPage }) );',
'  }, 2000);',
'})();',
'',
'// Translate form labels (messages registered server-side by region i18n-labels)',
'(function(){',
'  if (window._scaffMsgData) { apex.lang.addMessages(window._scaffMsgData); }',
'  var labelMap = {',
'    ''P31_CONTACT'':        ''SCAFF.MR.FORM.CONTACT'',',
'    ''P31_WERFLEIDER'':     ''SCAFF.MR.FORM.WERFLEIDER'',',
'    ''P31_GSM'':            ''SCAFF.MR.FORM.GSM'',',
'    ''P31_DATUM'':          ''SCAFF.MR.FORM.DELIVERY_DATE'',',
'    ''P31_TRANSPORT_DONE'': ''SCAFF.MR.FORM.TRANSPORT'',',
'    ''P31_VERVOER'':        ''SCAFF.MR.FORM.VERVOER'',',
'    ''P31_LADER'':          ''SCAFF.MR.FORM.LADER'',',
'    ''P31_UUR'':            ''SCAFF.MR.FORM.UUR'',',
'    ''P31_AANHOUDEN'':      ''SCAFF.MR.FORM.AANHOUDEN'',',
'    ''P31_OPMERKING'':      ''SCAFF.MR.FORM.OPMERKING''',
'  };',
'  Object.keys(labelMap).forEach(function(itemId) {',
'    var msg = apex.lang.getMessage(labelMap[itemId]);',
'    if (!msg || msg === labelMap[itemId]) { return; }',
'    var lbl = document.querySelector(''label[for="'' + itemId + ''"]'');',
'    if (lbl) {',
'      var tn = lbl.childNodes[0];',
'      if (tn && tn.nodeType === 3) { tn.textContent = msg; }',
'      else { lbl.prepend(document.createTextNode(msg)); }',
'    }',
'  });',
'  var msgSave = apex.lang.getMessage(''SCAFF.MR.FORM.BTN.SAVE'');',
'  var msgCancel = apex.lang.getMessage(''SCAFF.MR.FORM.BTN.CANCEL'');',
'  if (msgSave && msgSave !== ''SCAFF.MR.FORM.BTN.SAVE'') {',
'    document.querySelectorAll(''button.t-Button--hot'').forEach(function(b){',
'      if (/Opslaan/i.test(b.textContent.trim())) { b.textContent = msgSave; }',
'    });',
'  }',
'  if (msgCancel && msgCancel !== ''SCAFF.MR.FORM.BTN.CANCEL'') {',
'    document.querySelectorAll(''button.t-Button:not(.t-Button--hot)'').forEach(function(b){',
'      if (/Annuleren/i.test(b.textContent.trim())) { b.textContent = msgCancel; }',
'    });',
'  }',
'})();',
'',
'// Translate drawer menu',
'(function() {',
'  var translations = {',
'    ''nl'': { ''Home'': ''Home'', ''Materiaal aanvraag'': ''Materiaal aanvraag'', ''Retour aanvraag'': ''Retour aanvraag'', ''Transfer aanvraag'': ''Transfer aanvraag'', ''Inspectie'': ''Inspectie'', ''Mijn aanvragen'': ''Mijn aanvragen'' },',
'    ''en'': { ''Home'': ''Home'', ''Materiaal aanvraag'': ''Material request'', ''Retour aanvraag'': ''Return request'', ''Transfer aanvraag'': ''Transfer request'', ''Inspectie'': ''Inspection'', ''Mijn aanvragen'': ''My requests'' },',
'    ''fr'': { ''Home'': ''Accueil'', ''Materiaal aanvraag'': ''Demande de materiel'', ''Retour aanvraag'': ''Demande de retour'', ''Transfer aanvraag'': ''Demande de transfert'', ''Inspectie'': ''Inspection'', ''Mijn aanvragen'': ''Mes demandes'' },',
unistr('    ''de'': { ''Home'': ''Startseite'', ''Materiaal aanvraag'': ''Materialanforderung'', ''Retour aanvraag'': ''R\00FCcksendung'', ''Transfer aanvraag'': ''Transferanforderung'', ''Inspectie'': ''Inspektion'', ''Mijn aanvragen'': ''Meine Anfragen'' },'),
unistr('    ''pl'': { ''Home'': ''Strona g\0142\00F3wna'', ''Materiaal aanvraag'': ''Zam\00F3wienie materia\0142u'', ''Retour aanvraag'': ''Zwrot'', ''Transfer aanvraag'': ''Przeniesienie'', ''Inspectie'': ''Inspekcja'', ''Mijn aanvragen'': ''Moje zg\0142oszenia'' },'),
unistr('    ''ru'': { ''Home'': ''\0413\043B\0430\0432\043D\0430\044F'', ''Materiaal aanvraag'': ''\0417\0430\044F\0432\043A\0430 \043D\0430 \043C\0430\0442\0435\0440\0438\0430\043B'', ''Retour aanvraag'': ''\0412\043E\0437\0432\0440\0430\0442'', ''Transfer aanvraag'': ''\041F\0435\0440\0435\043C\0435\0449\0435\043D\0438\0435'', ''Inspectie'': ''\0418\043D\0441\043F\0435\043A\0446\0438\044F'', ''Mijn aanvragen'': ''\041C\043E\0438 \0437\0430\044F\0432\043A\0438'' },'),
unistr('    ''ar'': { ''Home'': ''\0627\0644\0635\0641\062D\0629 \0627\0644\0631\0626\064A\0633\064A\0629'', ''Materiaal aanvraag'': ''\0637\0644\0628 \0645\0648\0627\062F'', ''Retour aanvraag'': ''\0637\0644\0628 \0625\0631\062C\0627\0639'', ''Transfer aanvraag'': ''\0637\0644\0628 \0646\0642\0644'', ''Inspectie'': ''\0641\062D\0635'', ''Mijn aanvragen'': ''\0637\0644\0628\0627\062A\064A'' },'),
unistr('    ''tr'': { ''Home'': ''Ana sayfa'', ''Materiaal aanvraag'': ''Malzeme talebi'', ''Retour aanvraag'': ''\0130ade talebi'', ''Transfer aanvraag'': ''Transfer talebi'', ''Inspectie'': ''Denetim'', ''Mijn aanvragen'': ''Taleplerim'' }'),
'  };',
'  var lang = (document.documentElement.lang || ''nl'').toLowerCase().substring(0, 2);',
'  var t = translations[lang] || translations[''nl''];',
