'    into :P31_FROM_DISPLAY, :P31_FROM_CUSTOMER',
'    from scaff_po',
'   where po_id = to_number(:P31_FROM_PO);',
'exception when no_data_found then',
'  :P31_FROM_DISPLAY := null; :P31_FROM_CUSTOMER := null;',
'end;',
'begin',
'  select po_display, customer_name',
'    into :P31_TO_DISPLAY, :P31_TO_CUSTOMER',
'    from scaff_po',
'   where po_id = to_number(:P31_TO_PO);',
'exception when no_data_found then',
'  :P31_TO_DISPLAY := null; :P31_TO_CUSTOMER := null;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P31_FROM_PO'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>10006314563160798
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(10006440526160798)
,p_process_sequence=>5
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Load existing transfer'
,p_static_id=>'load-transfer'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'if PKG_SCAFF_REQ.can_edit_transfer(to_number(:P31_TRANSFER_ID)) = ''N'' then',
'  raise_application_error(-20001, ''Not allowed'');',
'end if;',
'select from_po_id, to_po_id, email_partner, contact_name, site_manager, gsm,',
'       transport_done, vervoer_code, lader_code,',
'       to_char(delivery_date,''fmDDMonYYYY'',''NLS_DATE_LANGUAGE=ENGLISH''),',
'       delivery_hour,',
'       case when hold_flag = ''Y'' then ''Y'' else ''N'' end,',
'       remark',
'  into :P31_FROM_PO, :P31_TO_PO, :P31_EMAIL_PARTNER, :P31_CONTACT, :P31_WERFLEIDER, :P31_GSM,',
'       :P31_TRANSPORT_DONE, :P31_VERVOER, :P31_LADER,',
'       :P31_DATUM, :P31_UUR,',
'       :P31_AANHOUDEN, :P31_OPMERKING',
'  from scaff_transfer_request',
' where transfer_id = to_number(:P31_TRANSFER_ID);'))
,p_process_clob_language=>'PLSQL'
,p_process_when=>'P31_TRANSFER_ID'
,p_process_when_type=>'ITEM_IS_NOT_NULL'
,p_internal_uid=>10006440526160798
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(10006587612160798)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Save transfer request'
,p_static_id=>'save-transfer-request'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_datum    date := to_date(:P31_DATUM,''DD-MON-YYYY'');',
'  l_min      date := PKG_SCAFF_REQ.next_business_day(trunc(sysdate),5);',
'  l_done     varchar2(1) := case when :P31_TRANSPORT_DONE in (''Y'',''1'') then ''Y'' else ''N'' end;',
'  l_hold     varchar2(1) := case when :P31_AANHOUDEN in (''Y'',''1'') then ''Y'' else ''N'' end;',
'  l_vervoer  varchar2(20) := case when l_done = ''Y'' then null else :P31_VERVOER end;',
'  l_lader    varchar2(20) := case when l_done = ''Y'' then null else :P31_LADER end;',
'  l_err      boolean := false;',
'  l_email    varchar2(200) := trim(:P31_EMAIL_PARTNER);',
'begin',
'  if l_email is null then',
'    apex_error.add_error(',
'      p_message          => apex_lang.message(''SCAFF.TR.FORM.EMAIL.REQ''),',
'      p_display_location => apex_error.c_inline_with_field_and_notif,',
'      p_page_item_name   => ''P31_EMAIL_PARTNER'');',
'    l_err := true;',
'  elsif not regexp_like(l_email, ''^[^@[:space:]]+@[^@[:space:]]+\.[^@[:space:]]+$'') then',
'    apex_error.add_error(',
'      p_message          => apex_lang.message(''SCAFF.TR.FORM.EMAIL.INVALID''),',
'      p_display_location => apex_error.c_inline_with_field_and_notif,',
'      p_page_item_name   => ''P31_EMAIL_PARTNER'');',
'    l_err := true;',
'  end if;',
'',
'  if l_done = ''N'' then',
'    if PKG_SCAFF_REQ.is_business_day(l_datum) = ''N'' then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.MR.FORM.DATE.WEEKEND''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P31_DATUM'');',
'      l_err := true;',
'    end if;',
'    if l_datum < l_min then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.MR.FORM.DATE.TOOSOON''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P31_DATUM'');',
'      l_err := true;',
'    end if;',
'    if l_vervoer is null then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.RR.FORM.VERVOER.REQ''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P31_VERVOER'');',
'      l_err := true;',
'    end if;',
'    if l_lader is null then',
'      apex_error.add_error(',
'        p_message          => apex_lang.message(''SCAFF.RR.FORM.LADER.REQ''),',
'        p_display_location => apex_error.c_inline_with_field_and_notif,',
'        p_page_item_name   => ''P31_LADER'');',
'      l_err := true;',
'    end if;',
'  end if;',
'  if l_err then',
'    return;',
'  end if;',
'',
'  if :P31_TRANSFER_ID is null then',
'    insert into scaff_transfer_request (',
'      from_po_id, to_po_id, email_partner,',
'      contact_name, site_manager, gsm,',
'      transport_done, vervoer_code, lader_code,',
'      delivery_date, delivery_hour,',
'      hold_flag, remark',
'    ) values (',
'      to_number(:P31_FROM_PO), to_number(:P31_TO_PO), l_email,',
'      :P31_CONTACT, :P31_WERFLEIDER, :P31_GSM,',
'      l_done, l_vervoer, l_lader,',
'      l_datum, :P31_UUR,',
'      l_hold, :P31_OPMERKING',
'    );',
'    apex_application.g_print_success_message := apex_lang.message(''SCAFF.TR.FORM.SAVED'');',
'    for r in (',
'      select ''P31_EMAIL_PARTNER'' as nm from dual union all',
'      select ''P31_CONTACT'' from dual union all',
'      select ''P31_WERFLEIDER'' from dual union all',
'      select ''P31_GSM'' from dual union all',
'      select ''P31_TRANSPORT_DONE'' from dual union all',
'      select ''P31_VERVOER'' from dual union all',
'      select ''P31_LADER'' from dual union all',
'      select ''P31_DATUM'' from dual union all',
'      select ''P31_AANHOUDEN'' from dual union all',
'      select ''P31_OPMERKING'' from dual',
'    ) loop',
'      apex_util.set_session_state(r.nm, null);',
'    end loop;',
'  else',
'    if PKG_SCAFF_REQ.can_edit_transfer(to_number(:P31_TRANSFER_ID)) = ''N'' then',
'      raise_application_error(-20001, ''Not allowed'');',
'    end if;',
'    update scaff_transfer_request',
'       set email_partner  = l_email,',
'           contact_name   = :P31_CONTACT,',
'           site_manager   = :P31_WERFLEIDER,',
'           gsm            = :P31_GSM,',
'           transport_done = l_done,',
'           vervoer_code   = l_vervoer,',
'           lader_code     = l_lader,',
'           delivery_date  = l_datum,',
'           delivery_hour  = :P31_UUR,',
'           hold_flag      = l_hold,',
'           remark         = :P31_OPMERKING',
'     where transfer_id = to_number(:P31_TRANSFER_ID);',
'    apex_application.g_print_success_message := apex_lang.message(''SCAFF.TR.FORM.SAVED.UPDATE'');',
'  end if;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>10006587612160798
);
end;
